options.css:
@import url('https://fonts.googleapis.com/css2?family=Orbitron:wght@500;700;800;900&display=swap');

:root{
  --bg: #060d18;
  --bg2: #091425;
  --panel: #071a34;
  --panel2: #081a31;
  --card: #07182d;
  --line: rgba(73, 134, 255, 0.18);
  --line-strong: rgba(73, 134, 255, 0.32);
  --text: #f1f6ff;
  --muted: #8ea7cc;
  --green: #00e38c;
  --green-d: #00b96f;
  --red: #ff5f72;
  --red-d: #d84057;
  --yellow: #ffd348;
  --blue: #4ea0ff;
  --cyan: #5bc0ff;
  --shadow: 0 0 0 1px rgba(255,255,255,0.02), 0 14px 30px rgba(0,0,0,0.35);
  --radius-xl: 34px;
  --radius-lg: 20px;
  --radius-md: 14px;
  --radius-sm: 10px;
}

*{
  box-sizing: border-box;
}

html, body{
  margin: 0;
  padding: 0;
  background:
    radial-gradient(circle at top left, rgba(54,109,212,0.12), transparent 22%),
    linear-gradient(180deg, #08111e 0%, #050b15 100%);
  color: var(--text);
  font-family: "Orbitron", sans-serif;
}

.caa-page{
  width: 100%;
  min-height: 100vh;
  padding: clamp(6px, 0.6vw, 10px);
  background: transparent;
}

.caa-shell{
  width: 100%;
  max-width: 100%;
  border-radius: clamp(16px, 1.2vw, 26px);
  border: 1px solid rgba(255,255,255,0.04);
  background: linear-gradient(180deg, rgba(10,18,31,0.97), rgba(6,12,22,0.98));
  box-shadow: var(--shadow);
  padding: clamp(8px, 0.8vw, 14px);
}

/* header */
.caa-header{
  padding: clamp(4px, 0.4vw, 6px) clamp(6px, 0.5vw, 8px) clamp(10px, 0.9vw, 14px);
}

.caa-title{
  text-align: center;
  font-size: clamp(18px, 1.6vw, 28px);
  font-weight: 900;
  letter-spacing: clamp(0.5px, 0.08vw, 1.3px);
  color: #ffffff;
}

/* layout */
.caa-layout{
  display: grid;
  grid-template-columns: minmax(0, 1fr) clamp(260px, 20vw, 330px);
  gap: clamp(8px, 0.8vw, 14px);
}

.caa-left{
  display: flex;
  flex-direction: column;
  gap: clamp(10px, 1vw, 16px);
}

/* section */
.system-section{
  border-radius: 18px;
  border: 1px solid var(--line);
  background: linear-gradient(180deg, rgba(6,21,43,0.97), rgba(5,15,28,0.98));
  box-shadow: var(--shadow);
  padding: clamp(8px, 0.8vw, 12px);
}

.rounded-bottom{
  border-radius: 28px;
}

.section-head{
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 2px 2px clamp(8px, 0.8vw, 12px);
}

.section-title{
  font-size: clamp(14px, 1vw, 18px);
  font-weight: 900;
  color: #ffffff;
  letter-spacing: 0.8px;
}

.tank-grid{
  display: grid;
  gap: clamp(8px, 0.8vw, 12px);
}

.acid-grid{
  grid-template-columns: repeat(4, minmax(0, 1fr));
}

.alk-grid{
  grid-template-columns: repeat(3, minmax(0, 1fr));
}

/* tank card */
.tank-card{
  border-radius: 16px;
  border: 1px solid rgba(83, 151, 255, 0.16);
  background: linear-gradient(180deg, rgba(5,28,58,0.95), rgba(4,18,34,0.98));
  box-shadow: inset 0 0 0 1px rgba(255,255,255,0.02);
  padding: clamp(8px, 0.8vw, 12px);
}

.tank-card-head{
  position: relative;
  display: flex;
  justify-content: center;
  align-items: center;
  margin-bottom: clamp(8px, 0.7vw, 10px);
}

.tank-name{
  text-align: center;
  width: 100%;
  font-size: clamp(11px, 0.9vw, 15px);
  font-weight: 900;
  color: #ffffff;
}

.tank-sub{
  font-size: 9px;
  color: #a8bfdf;
  letter-spacing: 0.5px;
}

.tank-badge{
  position: absolute;
  right: 0;
  top: 0;
  padding: 7px 12px;
  border-radius: 999px;
  font-size: 9px;
  font-weight: 800;
  letter-spacing: 0.6px;
  white-space: nowrap;
}

.tank-badge.running{
  background: linear-gradient(180deg, var(--green), var(--green-d));
  color: #04140c;
}

.tank-badge.standby{
  background: linear-gradient(180deg, #8193b1, #64758e);
  color: #ffffff;
}

/* body */
.tank-body{
  display: grid;
  grid-template-columns: clamp(100px, 9vw, 140px) 1fr;
  gap: clamp(8px, 0.8vw, 12px);
  align-items: center;
}

/* visual */
.tank-visual-block{
  display: flex;
  align-items: center;
  gap: clamp(5px, 0.5vw, 8px);
}

.tank-scale{
  width: clamp(30px, 2.5vw, 42px);
  height: clamp(130px, 11vw, 175px);
  position: relative;
}

.tank-scale span{
  position: absolute;
  right: 0;
  font-size: clamp(7px, 0.75vw, 9.5px);
  color: #b9cff0;
  font-weight: 700;
}

.tank-scale span:nth-child(1){
  top: 0;
}

.tank-scale span:nth-child(2){
  bottom: calc((80 / 560) * clamp(130px, 11vw, 175px) - 6px);
}

.tank-scale span:nth-child(3){
  bottom: 0;
  opacity: 0;
}

.tank-wrap{
  display: flex;
  align-items: center;
  justify-content: center;
}

.tank{
  position: relative;
  width: clamp(68px, 5.5vw, 95px);
  height: clamp(130px, 11vw, 175px);
  border-radius: clamp(12px, 1vw, 18px);
  border: 2px solid rgba(255,255,255,0.58);
  background: linear-gradient(180deg, rgba(255,255,255,0.10), rgba(255,255,255,0.03));
  overflow: hidden;
  box-shadow: inset 0 0 20px rgba(255,255,255,0.04);
}

.tank-top-dash{
  position: absolute;
  top: 6px;
  left: 10px;
  right: 14px;
  height: 6px;
  border-top: 3px dashed rgba(20,28,44,0.95);
  z-index: 5;
}

.tank-fill{
  position: absolute;
  left: 0;
  right: 0;
  bottom: 0;
}

.tank-fill.green-fill{
  background: linear-gradient(180deg, #8be8b4 0%, #2fd97c 100%);
}

.tank-fill.red-fill{
  background: linear-gradient(180deg, #ff8d8d 0%, #ff5d5d 100%);
}

.tank-center-value{
  position: absolute;
  left: 0;
  right: 0;
  top: 50%;
  transform: translateY(-50%) rotate(-90deg);
  text-align: center;
  font-size: clamp(8px, 0.7vw, 11px);
  font-weight: 900;
  color: rgba(255,255,255,0.88);
  z-index: 6;
}

.tank-zones{
  position: absolute;
  inset: 0;
  z-index: 3;
  pointer-events: none;
}

.zone{
  position: absolute;
  left: 6px;
  font-size: clamp(7px, 0.65vw, 9px);
  font-weight: 700;
  color: rgba(255,255,255,0.72);
}

.zone.high{
  top: 10px;
}

.zone.low{
  bottom: 12px;
}

.tank-ruler{
  position: absolute;
  right: 6px;
  top: 10px;
  bottom: 8px;
  width: clamp(9px, 0.8vw, 12px);
  display: flex;
  flex-direction: column;
  justify-content: space-between;
  z-index: 7;
}

.tank-ruler span{
  display: block;
  height: 4px;
  background: rgba(240,245,255,0.75);
  border-radius: 2px;
}

/* metrics */
.tank-metrics{
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: clamp(6px, 0.6vw, 8px);
}

.metric{
  min-height: 58px;
  height: clamp(46px, 4vw, 54px);
  border-radius: 10px;
  padding: 6px 12px;
  border: 1px solid rgba(255,255,255,0.06);
  background: rgba(255,255,255,0.02);
  display: flex;
  flex-direction: column;
  justify-content: center;
  gap: 3px;
}

.metric.good{
  background: linear-gradient(145deg, #13443c, #0e6742);
  color:#07c950;
  border:1px solid #0e6742;
  box-shadow: 0 0 10px rgba(7,201,80,0.18);
}

.metric.good span,
.metric.good strong{
  color:#07c950;
}

.metric.danger{
  background: linear-gradient(145deg,#4a1f22,#7a2c34);
  color:#ff5a66;
  border:1px solid #8f3a44;
  box-shadow:0 0 10px rgba(255,90,102,0.18);
}

.metric.danger span,
.metric.danger strong{
  color:#ff5a66;
}

.metric.neutral{
  background:#1a2230;
  border:1px solid #8a98b3;
}

.metric.neutral span,
.metric.neutral strong{
  color:#cfd8f6;
}

.metric.wide{
  grid-column: span 2;
}

.metric span{
  font-size: clamp(7px, 0.6vw, 9px) !important;
  font-weight: 700;
  letter-spacing: 0.4px;
  margin: 0;
}

.metric strong{
  font-size: clamp(11px, 0.95vw, 16px) !important;
  font-weight: 900;
  margin: 0;
}

/* alarm panel */
.alarm-panel{
  border-radius: 18px;
  border: 1px solid var(--line);
  background:
    radial-gradient(circle at top left, rgba(78,160,255,0.08), transparent 26%),
    linear-gradient(180deg, rgba(7,18,33,0.98), rgba(5,12,22,0.98));
  box-shadow: var(--shadow);
  padding: clamp(10px, 0.8vw, 14px);
  display: flex;
  flex-direction: column;
  min-height: 100%;
}

/* header */
.alarm-panel-header{
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 14px;
}

.alarm-panel-title{
  font-size: clamp(14px, 1vw, 18px);
  font-weight: 900;
  color: #ffffff;
  letter-spacing: 0.5px;
}

.alarm-live-pill{
  padding: 5px 10px;
  border-radius: 999px;
  font-size: 8px;
  font-weight: 800;
  letter-spacing: 0.8px;
  color: #7fd8ff;
  border: 1px solid rgba(91,192,255,0.30);
  background: rgba(91,192,255,0.08);
  box-shadow: 0 0 10px rgba(91,192,255,0.10);
}

/* summary */
.alarm-summary{
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: clamp(8px, 0.6vw, 10px);
  margin-bottom: 14px;
}

.summary-box{
  min-height: clamp(62px, 5vw, 78px);
  border-radius: 14px;
  padding: 10px;
  border: 1px solid rgba(255,255,255,0.06);
  background: linear-gradient(180deg, rgba(255,255,255,0.03), rgba(255,255,255,0.015));
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  position: relative;
  overflow: hidden;
}

.summary-box::before{
  content:"";
  position:absolute;
  inset:0;
  background: linear-gradient(180deg, rgba(255,255,255,0.04), transparent 40%);
  pointer-events:none;
}

.summary-label{
  font-size: 8px;
  margin-bottom: 6px;
  color: #dce8fa;
  letter-spacing: 0.7px;
}

.summary-value{
  font-size: clamp(22px, 1.8vw, 30px);
  line-height: 1;
  font-weight: 900;
  color: #ffffff;
}

.summary-box.critical{
  border-color: rgba(255,95,114,0.34);
  box-shadow: inset 0 0 18px rgba(255,95,114,0.05), 0 0 14px rgba(255,95,114,0.08);
}

.summary-box.warning{
  border-color: rgba(255,211,72,0.34);
  box-shadow: inset 0 0 18px rgba(255,211,72,0.05), 0 0 14px rgba(255,211,72,0.06);
}

.summary-box.info{
  border-color: rgba(78,160,255,0.34);
  box-shadow: inset 0 0 18px rgba(78,160,255,0.05), 0 0 14px rgba(78,160,255,0.06);
}

/* featured critical */
.featured-alarm{
  border-radius: 16px;
  padding: 14px;
  margin-bottom: 14px;
  position: relative;
  overflow: hidden;
  border: 1px solid rgba(255,255,255,0.08);
}

.featured-alarm::before{
  content:"";
  position:absolute;
  inset:0;
  background: linear-gradient(180deg, rgba(255,255,255,0.04), transparent 42%);
  pointer-events:none;
}

.featured-alarm.critical{
  border-color: rgba(255,95,114,0.38);
  background:
    radial-gradient(circle at top right, rgba(255,95,114,0.10), transparent 30%),
    linear-gradient(180deg, rgba(65,15,24,0.55), rgba(22,11,19,0.85));
  box-shadow:
    inset 0 0 24px rgba(255,95,114,0.05),
    0 0 18px rgba(255,95,114,0.08);
}

.featured-top{
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 10px;
}

.featured-tag{
  font-size: 8px;
  letter-spacing: 0.9px;
  color: #ffb3bc;
}

.featured-time{
  font-size: 9px;
  color: #ffd6dc;
}

.featured-title{
  font-size: clamp(11px, 0.9vw, 14px);
  font-weight: 900;
  color: #ffffff;
  line-height: 1.4;
  margin-bottom: 8px;
}

.featured-sub{
  font-size: 9px;
  color: #f0c9d0;
  line-height: 1.45;
}

/* timeline title */
.alarm-timeline-label{
  font-size: 8px;
  color: #8ea7cc;
  letter-spacing: 1px;
  margin-bottom: 10px;
}

/* list */
.alarm-list{
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.alarm-item{
  min-height: 78px;
  border-radius: 16px;
  border: 1px solid rgba(255,255,255,0.06);
  background:
    linear-gradient(180deg, rgba(255,255,255,0.028), rgba(255,255,255,0.012));
  display: grid;
  grid-template-columns: 6px 1fr;
  overflow: hidden;
  transition: transform 0.15s ease, box-shadow 0.15s ease;
}

.alarm-item:hover{
  transform: translateY(-1px);
}

.alarm-rail{
  height: 100%;
}

.alarm-item.critical .alarm-rail{
  background: linear-gradient(180deg, #ff5f72, #d84057);
}

.alarm-item.warning .alarm-rail{
  background: linear-gradient(180deg, #ffd348, #d8ae22);
}

.alarm-item.info .alarm-rail{
  background: linear-gradient(180deg, #4ea0ff, #2d7fe1);
}

.alarm-item.neutral .alarm-rail{
  background: linear-gradient(180deg, #95a3bb, #6e7c95);
}

.alarm-item.critical{
  box-shadow: 0 0 14px rgba(255,95,114,0.06);
}

.alarm-item.warning{
  box-shadow: 0 0 14px rgba(255,211,72,0.05);
}

.alarm-item.info{
  box-shadow: 0 0 14px rgba(78,160,255,0.05);
}

.alarm-item.neutral{
  box-shadow: 0 0 14px rgba(149,163,187,0.04);
}

.alarm-content{
  padding: 12px 14px;
  display: flex;
  flex-direction: column;
  justify-content: center;
}

.alarm-row-top{
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 10px;
  margin-bottom: 10px;
}

.alarm-severity-wrap{
  display: flex;
  align-items: center;
  gap: 8px;
}

.alarm-dot{
  width: 8px;
  height: 8px;
  border-radius: 50%;
  background: currentColor;
  flex: 0 0 8px;
}

.alarm-item.critical .alarm-dot{
  color: #ff5f72;
  box-shadow: 0 0 8px rgba(255,95,114,0.45);
}

.alarm-item.warning .alarm-dot{
  color: #ffd348;
  box-shadow: 0 0 8px rgba(255,211,72,0.35);
}

.alarm-item.info .alarm-dot{
  color: #4ea0ff;
  box-shadow: 0 0 8px rgba(78,160,255,0.35);
}

.alarm-item.neutral .alarm-dot{
  color: #95a3bb;
}

.alarm-severity{
  font-size: 8px;
  font-weight: 800;
  letter-spacing: 0.7px;
  color: #ffffff;
  padding: 4px 8px;
  border-radius: 999px;
  border: 1px solid rgba(255,255,255,0.06);
  background: rgba(255,255,255,0.04);
}

.alarm-item.critical .alarm-severity{
  color: #ffb6c0;
  border-color: rgba(255,95,114,0.25);
  background: rgba(255,95,114,0.08);
}

.alarm-item.warning .alarm-severity{
  color: #ffe27c;
  border-color: rgba(255,211,72,0.22);
  background: rgba(255,211,72,0.08);
}

.alarm-item.info .alarm-severity{
  color: #8fccff;
  border-color: rgba(78,160,255,0.22);
  background: rgba(78,160,255,0.08);
}

.alarm-item.neutral .alarm-severity{
  color: #c7d4e8;
  border-color: rgba(149,163,187,0.18);
  background: rgba(149,163,187,0.08);
}

.alarm-time{
  font-size: 9px;
  color: #b7c9e6;
  white-space: nowrap;
  padding: 3px 7px;
  border-radius: 999px;
  background: rgba(255,255,255,0.04);
}

.alarm-msg{
  font-size: clamp(9px, 0.75vw, 11px);
  color: #ffffff;
  line-height: 1.45;
  font-weight: 700;
}

/* responsive */
@media (max-width: 1600px){
  .acid-grid{
    grid-template-columns: repeat(2, 1fr);
  }

  .alk-grid{
    grid-template-columns: repeat(2, 1fr);
  }
}

@media (max-width: 1200px){
  .caa-layout{
    grid-template-columns: 1fr;
  }

  .acid-grid,
  .alk-grid{
    grid-template-columns: repeat(2, 1fr);
  }
}

@media (max-width: 900px){
  .acid-grid,
  .alk-grid{
    grid-template-columns: 1fr;
  }

  .tank-body{
    grid-template-columns: 1fr;
  }

  .tank-visual-block{
    justify-content: center;
  }

  .caa-title{
    font-size: 20px;
  }
}

.trend-section{
  margin-top: 14px;
}

.trend-grid{
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 14px;
}

.trend-card{
  border-radius: 18px;
  border: 1px solid var(--line);
  background: linear-gradient(180deg, rgba(6,21,43,0.97), rgba(5,15,28,0.98));
  box-shadow: var(--shadow);
  padding: 12px;
  min-height: 250px;
}

.trend-header{
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 10px;
  margin-bottom: 10px;
}

.trend-title{
  font-size: 13px;
  font-weight: 900;
  color: #ffffff;
  letter-spacing: 0.5px;
}

.trend-last{
  font-size: 10px;
  font-weight: 800;
  color: #07c950;
  padding: 5px 10px;
  border-radius: 999px;
  border: 1px solid #0e6742;
  background: linear-gradient(145deg, #13443c, #0e6742);
}

.trend-last.danger{
  color: #ff5a66;
  border: 1px solid #8f3a44;
  background: linear-gradient(145deg,#4a1f22,#7a2c34);
}

.trend-chart{
  width: 100%;
  height: 190px;
  border-radius: 14px;
  border: 1px solid rgba(255,255,255,0.05);
  background:
    linear-gradient(180deg, rgba(255,255,255,0.02), rgba(255,255,255,0.01));
  position: relative;
  overflow: hidden;
}

.trend-svg{
  width: 100%;
  height: 100%;
  display: block;
}

.limit-high,
.limit-low{
  stroke-width: 2;
  stroke-dasharray: 6 5;
}

.limit-high{
  stroke: rgba(255,95,114,0.85);
}

.limit-low{
  stroke: rgba(120,170,255,0.75);
}

.limit-label{
  font-size: 11px;
  font-family: "Orbitron", sans-serif;
  font-weight: 700;
  letter-spacing: 0.5px;
}

.high-label{
  fill: #ff8b99;
}

.low-label{
  fill: #8fc8ff;
}

.trend-line{
  stroke-width: 3;
  stroke-linecap: round;
  stroke-linejoin: round;
}

.acid-line{
  stroke: #5bc0ff;
  filter: drop-shadow(0 0 4px rgba(91,192,255,0.35));
}

.alk-line{
  stroke: #07c950;
  filter: drop-shadow(0 0 4px rgba(7,201,80,0.30));
}

.danger-trend{
  stroke: #ff5a66;
  filter: drop-shadow(0 0 4px rgba(255,90,102,0.35));
}

.trend-point{
  stroke: #ffffff;
  stroke-width: 1.5;
}

.acid-point{
  fill: #5bc0ff;
}

.alk-point{
  fill: #07c950;
}

.danger-point{
  fill: #ff5a66;
}

.tank-center-value {
  display: none;
}

options.onInit:
// Sets the text from customProperties
const htmlgraphicsText = htmlNode.getElementById('htmlgraphics-text');

if (htmlgraphicsText) {
  htmlgraphicsText.textContent = customProperties.text;

  // Change the text color based on the theme
  if (theme.isDark) {
    htmlgraphicsText.style.color = 'green';
  } else {
    htmlgraphicsText.style.color = 'red';
  }
}

options.onRender:
try {
  const root = htmlNode;

  function getSeries(refId) {
    return (data.series || []).find(s => String(s.refId).toUpperCase() === refId);
  }

  function getSeriesAll(refId) {
    return (data.series || []).filter(s => String(s.refId).toUpperCase() === refId);
  }

  function field(series, name) {
    return series?.fields?.find(f => f.name === name) || null;
  }

  function arr(f) {
    if (!f) return [];
    if (f.values?.toArray) return f.values.toArray();
    if (f.values?.buffer) return Array.from(f.values.buffer);
    if (f.values?.get) {
      let out = [];
      for (let i = 0; i < f.values.length; i++) out.push(f.values.get(i));
      return out;
    }
    return Array.isArray(f.values) ? f.values : [];
  }

  function resetAllCAAValues() {
    root.querySelectorAll(".tank-card .metric strong").forEach(el => el.textContent = "--");
    root.querySelectorAll(".tank-card .metric").forEach(m => {
      m.classList.remove("good", "danger");
      m.classList.add("neutral");
    });
    root.querySelectorAll(".trend-last").forEach(el => {
      el.textContent = "LAST: --";
      el.classList.remove("danger");
    });
    root.querySelectorAll(".trend-chart").forEach(el => el.innerHTML = "");
  }

  resetAllCAAValues();

  function setMetric(card, labelText, valueText, state = "neutral") {
    if (!card) return;
    const m = [...card.querySelectorAll(".metric")].find(x =>
      String(x.querySelector("span")?.textContent || "")
        .toUpperCase()
        .includes(labelText.toUpperCase())
    );
    if (!m) return;

    m.classList.remove("good", "danger", "neutral");
    m.classList.add(state);

    const strong = m.querySelector("strong");
    if (strong) strong.textContent = valueText;
  }

  function disableMetric(card, labelText) {
    setMetric(card, labelText, "--", "neutral");
  }

  function greyUnusedMetric(card, labelText) {
    if (!card) return;

    const metric = [...card.querySelectorAll(".metric")].find(m =>
      String(m.querySelector("span")?.textContent || "")
        .toUpperCase()
        .includes(labelText.toUpperCase())
    );

    if (!metric) return;

    metric.classList.remove("good", "danger");
    metric.classList.add("neutral");

    // CDS-style grey
    metric.style.background = "linear-gradient(180deg, #5f6979, #4f5968)";
    metric.style.border = "1px solid #cfd6df";
    metric.style.boxShadow = "none";
    metric.style.opacity = "0.75";

    const span = metric.querySelector("span");
    const strong = metric.querySelector("strong");

    if (span) span.style.color = "#d9dee6";
    if (strong) {
      strong.textContent = "--";
      strong.style.color = "#f1f4f7";
    }
  }

  function disableTankCard(card) {
    if (!card) return;
    card.style.opacity = "0.48";

    card.querySelectorAll(".metric").forEach(m => {
      m.classList.remove("good", "danger");
      m.classList.add("neutral");
      const strong = m.querySelector("strong");
      if (strong) strong.textContent = "--";
    });

    const fill = card.querySelector(".tank-fill");
    if (fill) {
      fill.classList.remove("green-fill", "red-fill");
      fill.classList.add("red-fill");
      fill.style.height = "0%";
      fill.style.opacity = "0.35";
    }

    const badge = card.querySelector(".tank-badge");
    if (badge) {
      badge.classList.remove("running");
      badge.classList.add("standby");
      badge.textContent = "--";
    }
  }

  function getTankCard(titleText) {
    return [...root.querySelectorAll(".tank-card")].find(card =>
      String(card.querySelector(".tank-name")?.textContent || "")
        .trim()
        .toUpperCase() === titleText.toUpperCase()
    );
  }

  const acidT1 = getTankCard("DILUTED ACID T1");
  const acidT2 = getTankCard("DILUTED ACID T2");
  const acidCon1 = getTankCard("CONCENTRATED ACID T1");
  const acidCon2 = getTankCard("CONCENTRATED ACID T2");

  const alkT1 = getTankCard("DILUTED ALKALINE T1");
  const alkT2 = getTankCard("DILUTED ALKALINE T2");
  const alkCon1 = getTankCard("CONCENTRATED ALKALINE T1");


  [acidCon1, acidCon2, alkCon1].forEach(card => {
    if (!card) return;

    card.style.opacity = "1";


    card.querySelectorAll(".metric").forEach(m => {
      m.classList.remove("good", "danger");
      m.classList.add("neutral");
      const strong = m.querySelector("strong");
      if (strong) strong.textContent = "--";
    });


    const fill = card.querySelector(".tank-fill");
    if (fill) fill.style.opacity = "1";

    const center = card.querySelector(".tank-center-value");
    if (center) center.style.opacity = "1";
  });

  [
    acidT1,
    acidT2,
    acidCon1,
    acidCon2,
    alkT1,
    alkT2,
    alkCon1
  ].forEach(card => {
    greyUnusedMetric(card, "PUMP SPEED");
    greyUnusedMetric(card, "STATUS");
  });



  const acidLatest = getSeries("A");
  const alkLatest = getSeries("C");
  const acidTrend = getSeriesAll("B");
  const alkTrend = getSeriesAll("D");
  const levelPressureLatest = getSeriesAll("E");

  function getLevelPressureMap(seriesInput) {
    const seriesList = Array.isArray(seriesInput) ? seriesInput : [seriesInput];
    const map = {};

    seriesList.forEach(series => {
      if (!series) return;

      const valueField =
        field(series, "value") ||
        series.fields.find(f => f.type === "number");

      if (!valueField) return;

      const itemField = field(series, "item");
      const values = arr(valueField);
      const items = arr(itemField);

      for (let i = 0; i < values.length; i++) {
        let item = String(items[i] || "").toUpperCase();

        if (!item) {
          item = String(
            valueField.labels?.item ||
            valueField.config?.displayNameFromDS ||
            series.name ||
            ""
          ).toUpperCase();
        }

        if (item.includes("CON_ACID_T1")) item = "CON_ACID_T1";
        if (item.includes("CON_ACID_T2")) item = "CON_ACID_T2";
        if (item.includes("DIL_ACID_T1")) item = "DIL_ACID_T1";
        if (item.includes("DIL_ACID_T2")) item = "DIL_ACID_T2";
        if (item.includes("CON_ALK_T1")) item = "CON_ALK_T1";
        if (item.includes("DIL_ALK_T1")) item = "DIL_ALK_T1";
        if (item.includes("DIL_ALK_T2")) item = "DIL_ALK_T2";
        if (item.includes("ACID_SUPPLY")) item = "ACID_SUPPLY";
        if (item.includes("ALK_SUPPLY")) item = "ALK_SUPPLY";

        if (item) map[item] = Number(values[i]);
      }
    });

    return map;
  }

  function noDataTank(card) {
    if (!card) return;

    setMetric(card, "LEVEL", "--", "neutral");

    const fill = card.querySelector(".tank-fill");
    if (fill) {
      fill.style.height = "0%";
      fill.style.opacity = "0.2";
      fill.classList.remove("green-fill", "red-fill");
    }
  }

  function applyLevel(card, levelValue) {
    if (!card) return;

    if (!Number.isFinite(levelValue)) {
      noDataTank(card);
      return;
    }

    const isLow = levelValue < 75;
    if (isLow) {
      const tankName = card.querySelector(".tank-name")?.textContent?.trim() || "CAA TANK";
      addAlarm("critical", `${tankName} - LEVEL LOW (${Math.round(levelValue)} CM)`);
    }

    setMetric(card, "LEVEL", `${Math.round(levelValue)} CM`, isLow ? "danger" : "good");

    const fill = card.querySelector(".tank-fill");
    if (fill) {
      const pct = Math.max(0, Math.min(100, (levelValue / 560) * 100));
      fill.style.height = `${pct}%`;
      fill.style.opacity = "1";
      fill.classList.remove("green-fill", "red-fill");
      fill.classList.add(isLow ? "red-fill" : "green-fill");
    }
  }

  let alarmListData = [];

  function addAlarm(type, message) {
    alarmListData.push({
      type,
      message,
      time: new Date().toLocaleTimeString("en-GB", {
        hour: "2-digit",
        minute: "2-digit"
      })
    });
  }

  function renderCAAAlarms() {
    const alarmPanel = root.querySelector(".alarm-panel");
    if (!alarmPanel) return;

    alarmPanel.style.opacity = "1";
    alarmPanel.style.pointerEvents = "auto";

    // remove INFO box
    const infoBox = alarmPanel.querySelector(".summary-box.info");
    if (infoBox) infoBox.style.display = "none";

    const criticalCount = alarmListData.filter(a => a.type === "critical").length;
    const warningCount = alarmListData.filter(a => a.type === "warning").length;

    const criticalVal = alarmPanel.querySelector(".summary-box.critical .summary-value");
    const warningVal = alarmPanel.querySelector(".summary-box.warning .summary-value");

    if (criticalVal) criticalVal.textContent = criticalCount;
    if (warningVal) warningVal.textContent = warningCount;

    const featured = alarmPanel.querySelector(".featured-title");
    const featuredTime = alarmPanel.querySelector(".featured-time");

    const latestCritical = alarmListData.find(a => a.type === "critical");

    if (featured) featured.textContent = latestCritical ? latestCritical.message : "--";
    if (featuredTime) featuredTime.textContent = latestCritical ? latestCritical.time : "--";

    const list = alarmPanel.querySelector(".alarm-list");
    if (!list) return;

    if (!alarmListData.length) {
      list.innerHTML = `
        <div class="alarm-item neutral">
          <div class="alarm-rail"></div>
          <div class="alarm-content">
            <div class="alarm-row-top">
              <div class="alarm-severity-wrap">
                <span class="alarm-dot"></span>
                <span class="alarm-severity">--</span>
              </div>
              <div class="alarm-time">--</div>
            </div>
            <div class="alarm-msg">NO ACTIVE ALARM</div>
          </div>
        </div>
      `;
      return;
    }

    list.innerHTML = alarmListData.map(a => `
      <div class="alarm-item ${a.type}">
        <div class="alarm-rail"></div>
        <div class="alarm-content">
          <div class="alarm-row-top">
            <div class="alarm-severity-wrap">
              <span class="alarm-dot"></span>
              <span class="alarm-severity">${a.type === "critical" ? "CRITICAL" : "WARNING"}</span>
            </div>
            <div class="alarm-time">${a.time}</div>
          </div>
          <div class="alarm-msg">${a.message}</div>
        </div>
      </div>
    `).join("");
  }



  function applyLatest(series, tankMap, valueFieldName) {
    if (!series) return;

    const tankField = field(series, "tankNo");
    const valField = field(series, valueFieldName);
    const minField = field(series, valueFieldName.replace("_current", "_min"));
    const maxField = field(series, valueFieldName.replace("_current", "_max"));
    const statusField = field(series, "status");

    if (!valField) return;

    const tanks = arr(tankField);
    const vals = arr(valField);
    const mins = arr(minField);
    const maxs = arr(maxField);
    const statuses = arr(statusField);

    for (let i = 0; i < vals.length; i++) {
      let tankNo = String(tanks[i] || "").toUpperCase();

      if (!tankNo) {
        tankNo = String(
          valField.labels?.tankNo ||
          valField.config?.displayNameFromDS ||
          series.name ||
          ""
        ).toUpperCase();
      }

      const isAcid = valueFieldName.includes("acid");
      const isAlk = valueFieldName.includes("alkaline");

      if (tankNo === "1") tankNo = isAcid ? "ACID1" : isAlk ? "ALK1" : tankNo;
      if (tankNo === "2") tankNo = isAcid ? "ACID2" : isAlk ? "ALK2" : tankNo;

      if (tankNo.includes("ACID1")) tankNo = "ACID1";
      if (tankNo.includes("ACID2")) tankNo = "ACID2";
      if (tankNo.includes("ALK1")) tankNo = "ALK1";
      if (tankNo.includes("ALK2")) tankNo = "ALK2";
      const card = tankMap[tankNo];
      if (!card) continue;

      const val = Number(vals[i]);
      const min = Number(mins[i]);
      const max = Number(maxs[i]);
      const status = Number(statuses[i]);

      const bad = status === 2 || (
        Number.isFinite(val) &&
        Number.isFinite(min) &&
        Number.isFinite(max) &&
        (val < min || val > max)
      );

      if (bad) {
        const tankName = card.querySelector(".tank-name")?.textContent?.trim() || "CAA TANK";
        const label = valueFieldName.includes("acid") ? "ACID STRENGTH" : "ALKALINE STRENGTH";

        addAlarm(
          "warning",
          `${tankName} - ${label} OUT OF RANGE (${Number.isFinite(val) ? val.toFixed(2) : "--"})`
        );
      }

      const ok = status === 1 && !bad;



      setMetric(
        card,
        valueFieldName.includes("acid") ? "ACID STRENGTH" : "ALKALINE STRENGTH",
        Number.isFinite(val) ? val.toFixed(2) : "--",
        bad ? "danger" : ok ? "good" : "neutral"
      );

      const fill = card.querySelector(".tank-fill");
      if (fill) {
        fill.classList.remove("green-fill", "red-fill");
        fill.classList.add(bad ? "red-fill" : "green-fill");
        fill.style.height = "0%";
        fill.style.opacity = "0.35";
      }
    }
  }

  applyLatest(acidLatest, { ACID1: acidT1, ACID2: acidT2 }, "acid_current");
  applyLatest(alkLatest, { ALK1: alkT1, ALK2: alkT2 }, "alkaline_current");

  const lp = getLevelPressureMap(levelPressureLatest);

  applyLevel(acidCon1, lp.CON_ACID_T1);
  applyLevel(acidCon2, lp.CON_ACID_T2);
  applyLevel(acidT1, lp.DIL_ACID_T1);
  applyLevel(acidT2, lp.DIL_ACID_T2);

  applyLevel(alkCon1, lp.CON_ALK_T1);
  applyLevel(alkT1, lp.DIL_ALK_T1);
  applyLevel(alkT2, lp.DIL_ALK_T2);

  function buildRows(seriesInput, valueKey, minKey, maxKey) {
    const seriesList = Array.isArray(seriesInput) ? seriesInput : [seriesInput];
    const out = {};

    seriesList.forEach(series => {
      if (!series) return;

      const timeField =
        field(series, "_time") ||
        field(series, "Time") ||
        series.fields.find(f => f.type === "time");

      const valField = field(series, valueKey);
      const minField = field(series, minKey);
      const maxField = field(series, maxKey);
      const tankField = field(series, "tankNo");

      if (!valField) return;

      const times = arr(timeField);
      const vals = arr(valField);
      const mins = arr(minField);
      const maxs = arr(maxField);
      const tanks = arr(tankField);

      for (let i = 0; i < vals.length; i++) {
        let tankNo = String(tanks[i] || "").toUpperCase();

        if (!tankNo) {
          tankNo = String(
            valField.labels?.tankNo ||
            valField.config?.displayNameFromDS ||
            series.name ||
            ""
          ).toUpperCase();
        }

        const isAcid = valueKey.includes("acid");
        const isAlk = valueKey.includes("alkaline");

        if (tankNo === "1") tankNo = isAcid ? "ACID1" : isAlk ? "ALK1" : tankNo;
        if (tankNo === "2") tankNo = isAcid ? "ACID2" : isAlk ? "ALK2" : tankNo;

        if (tankNo.includes("ACID1")) tankNo = "ACID1";
        if (tankNo.includes("ACID2")) tankNo = "ACID2";
        if (tankNo.includes("ALK1")) tankNo = "ALK1";
        if (tankNo.includes("ALK2")) tankNo = "ALK2";

        if (!tankNo) continue;
        if (!out[tankNo]) out[tankNo] = [];

        out[tankNo].push({
          time: times[i],
          [valueKey]: vals[i],
          [minKey]: mins[i],
          [maxKey]: maxs[i]
        });
      }
    });

    return out;
  }

  function renderTrend(chartEl, lastEl, rows, valueKey, minKey, maxKey, cssLineClass, cssPointClass) {
    if (!chartEl) return;

    if (!rows.length) {
      chartEl.innerHTML = "";
      if (lastEl) lastEl.textContent = "LAST: --";
      return;
    }

    const values = rows.map(r => Number(r[valueKey])).filter(Number.isFinite);
    const mins = rows.map(r => Number(r[minKey])).filter(Number.isFinite);
    const maxs = rows.map(r => Number(r[maxKey])).filter(Number.isFinite);

    if (!values.length) {
      chartEl.innerHTML = "";
      if (lastEl) lastEl.textContent = "LAST: --";
      return;
    }

    const last = values[values.length - 1];
    const min = mins.length ? mins[mins.length - 1] : Math.min(...values);
    const max = maxs.length ? maxs[maxs.length - 1] : Math.max(...values);

    if (lastEl) {
      lastEl.textContent = `LAST: ${last.toFixed(2)}`;
      lastEl.classList.toggle("danger", Number.isFinite(min) && Number.isFinite(max) && (last < min || last > max));
    }

    let yMin = Math.min(...values, ...mins);
    let yMax = Math.max(...values, ...maxs);
    if (yMin === yMax) {
      yMin -= 1;
      yMax += 1;
    }

    const pad = (yMax - yMin) * 0.12;
    yMin -= pad;
    yMax += pad;

    const x = i => 20 + (i / Math.max(1, rows.length - 1)) * 560;
    const y = v => 165 - ((v - yMin) / (yMax - yMin)) * 130;

    const pts = rows.map((r, i) => `${x(i)},${y(Number(r[valueKey]))}`).join(" ");
    const lastX = rows.length === 1 ? 300 : x(rows.length - 1);
    const singleLine = rows.length === 1
      ? `<line x1="20" y1="${y(last)}" x2="580" y2="${y(last)}" class="trend-line ${cssLineClass}"/>`
      : `<polyline points="${pts}" class="trend-line ${cssLineClass}" fill="none"/>`;
    const yHigh = y(max);
    const yLow = y(min);

    chartEl.innerHTML = `
      <svg viewBox="0 0 600 190" class="trend-svg" preserveAspectRatio="none">
        <line x1="20" y1="${yHigh}" x2="580" y2="${yHigh}" class="limit-high"/>
        <text x="24" y="${yHigh - 8}" class="limit-label high-label">HIGH ${Number.isFinite(max) ? max.toFixed(2) : ""}</text>

        <line x1="20" y1="${yLow}" x2="580" y2="${yLow}" class="limit-low"/>
        <text x="24" y="${yLow - 8}" class="limit-label low-label">LOW ${Number.isFinite(min) ? min.toFixed(2) : ""}</text>

        ${singleLine}
        <circle cx="${lastX}" cy="${y(last)}" r="4.5" class="trend-point ${cssPointClass}"/>
      </svg>
    `;
  }

  const trendCards = [...root.querySelectorAll(".trend-card")];

  function trendByTitle(text) {
    return trendCards.find(c =>
      String(c.querySelector(".trend-title")?.textContent || "")
        .toUpperCase()
        .includes(text.toUpperCase())
    );
  }

  const acidRows = buildRows(acidTrend, "acid_current", "acid_min", "acid_max");
  const alkRows = buildRows(alkTrend, "alkaline_current", "alkaline_min", "alkaline_max");

  const acidT1Trend = trendByTitle("DILUTED ACID T1");
  const acidT2Trend = trendByTitle("DILUTED ACID T2");
  const alkT1Trend = trendByTitle("DILUTED ALKALINE T1");
  const alkT2Trend = trendByTitle("DILUTED ALKALINE T2");



  renderTrend(
    acidT1Trend?.querySelector(".trend-chart"),
    acidT1Trend?.querySelector(".trend-last"),
    acidRows.ACID1 || [],
    "acid_current", "acid_min", "acid_max",
    "acid-line", "acid-point"
  );

  renderTrend(
    acidT2Trend?.querySelector(".trend-chart"),
    acidT2Trend?.querySelector(".trend-last"),
    acidRows.ACID2 || [],
    "acid_current", "acid_min", "acid_max",
    "acid-line", "acid-point"
  );

  renderTrend(
    alkT1Trend?.querySelector(".trend-chart"),
    alkT1Trend?.querySelector(".trend-last"),
    alkRows.ALK1 || [],
    "alkaline_current", "alkaline_min", "alkaline_max",
    "alk-line", "alk-point"
  );

  renderTrend(
    alkT2Trend?.querySelector(".trend-chart"),
    alkT2Trend?.querySelector(".trend-last"),
    alkRows.ALK2 || [],
    "alkaline_current", "alkaline_min", "alkaline_max",
    "alk-line", "alk-point"
  );

  renderCAAAlarms();

} catch (err) {
  console.log("CAA detail dashboard render error:", err);
}
